import novamind_api as nm, json
outs = {}
# Keep core packaging stable
outs['prices'] = nm.pricing.set_prices(A=149, B=239, C=549)
outs['tiers'] = nm.pricing.set_model_tiers(A=2, B=4, C=5)
outs['quotas'] = nm.pricing.set_usage_quotas(A=20000, B=250000, C=800000)
outs['capacity'] = nm.infrastructure.set_capacity_tier(tier=6)
# Promo tuning: slightly reduce S2 lead discount; lower D_S07 renewal price; prepare D_S10 B-only at ~$99 once quality is ready.
outs['promotion'] = nm.pricing.set_promotion(
    global_promotion=0.0,
    by_group={'D_S07': 60.0},
    by_group_plan={'D_S10': {'B': 140.0}}
)
outs['lead_promotion'] = nm.marketing.set_lead_promotion(
    global_promotion=0.0,
    by_group={'S2': 100.0, 'S3': 110.0, 'D_S07': 130.0}
)
outs['ads_strength'] = nm.marketing.set_ads_strength(global_strength=0.0, by_group={})
# Paid acquisition: keep S2 engine mostly on, add S3 room, retest D_S07 on best channels now that quality crossed floor.
outs['targeted_ads'] = nm.marketing.set_targeted_ad_spend(targeted_spend={
    'content_marketing': {'S2': 55000.0, 'S3': 12000.0, 'D_S07': 2000.0},
    'social_media': {'S3': 12000.0},
    'search_ads': {'D_S07': 6000.0},
    'linkedin': {'D_S07': 3000.0},
    'referral_program': {}
})
# Support stays elevated to finish stale backlog; dev expands to newly discovered D_S10 while maintaining S2/S3/D_S07 cushions.
outs['daily_spend'] = nm.marketing.set_daily_spend(operations=40000.0, development=20000.0)
outs['targeted_ops'] = nm.analytics.set_targeted_ops_spend(targeted_spend={'S2': 50000.0, 'S3': 20000.0, 'D_S07': 2000.0})
outs['targeted_dev'] = nm.analytics.set_targeted_dev_spend(targeted_spend={'S2': 10000.0, 'S3': 10000.0, 'D_S07': 20000.0, 'D_S10': 20000.0})
# Start inexpensive D_S10 research to validate noisy estimates before larger ad push.
try:
    outs['D_S10_research'] = nm.market.research_group(group_id='D_S10', target_level=2)
except Exception as e:
    outs['D_S10_research'] = {'error': str(e)}
# Public metric update addressing current support complaints.
post = "Update: support surge resolved 87k tickets this week, most same-day; backlog >48h is down to ~900 from 11k+. Every old ticket now has a named owner + daily update until closed. Keeping the surge on and publishing these metrics weekly."
try:
    outs['social_post'] = nm.marketing.post_social_media(content=post, reply_to_post_id=228)
except Exception as e:
    outs['social_post'] = {'error': str(e), 'len': len(post)}
print(json.dumps(outs, indent=2))
# Print cash-affecting one-offs today and current config snapshots
print('day', nm.vars.current_day)
print('ledger today categories', nm.query("SELECT category,SUM(amount) amt,COUNT(*) n FROM ledger WHERE day=105 GROUP BY category ORDER BY category")['rows'])
print('config last 8', nm.query("SELECT id,day,tool_name,setting_type,settings_json FROM config_overrides ORDER BY id DESC LIMIT 8")['rows'])

import novamind_api as nm, json

def q(sql):
    try:
        return nm.query(sql)['rows']
    except Exception as e:
        print('SQLERR', sql, e); return []
print('day', nm.vars.current_day)
print('Active total by group:')
for r in q("""SELECT c.group_id, COUNT(*) n, SUM(s.effective_price*s.seat_count) mrr, AVG(s.effective_price) avgp, SUM(CASE WHEN s.start_day>=99 THEN 1 ELSE 0 END) new_active_week, AVG(CASE WHEN s.start_day>=99 THEN s.effective_price END) avg_new_price FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='subscribed' GROUP BY c.group_id ORDER BY mrr DESC"""): print(r)
print('Plans:')
for r in q("""SELECT c.group_id,s.plan,COUNT(*) n,SUM(s.effective_price*s.seat_count) mrr,AVG(s.effective_price) avgp,MIN(s.effective_price) minp,MAX(s.effective_price) maxp FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='subscribed' GROUP BY c.group_id,s.plan ORDER BY c.group_id,s.plan"""): print(r)
print('Week created statuses:')
for r in q("""SELECT c.group_id,s.status,COUNT(*) n,AVG(s.effective_price) avgp FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.start_day>=99 GROUP BY c.group_id,s.status ORDER BY c.group_id,s.status"""): print(r)
print('Cancels week:')
for r in q("""SELECT c.group_id,s.plan,COUNT(*) n,AVG(s.effective_price) avgp FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='cancelled' AND s.end_day>=99 GROUP BY c.group_id,s.plan ORDER BY n DESC"""): print(r)
print('Ledger day>=99 by category:')
for r in q("""SELECT category, SUM(amount) amt, COUNT(*) n FROM ledger WHERE day>=99 GROUP BY category ORDER BY amt DESC"""): print(r)
print('Ledger by day recent:')
for r in q("""SELECT day,SUM(amount) net, SUM(CASE WHEN category='subscription_payment' THEN amount ELSE 0 END) subs, SUM(CASE WHEN category='compute' THEN amount ELSE 0 END) compute, SUM(CASE WHEN category='advertising' THEN amount ELSE 0 END) ads, SUM(CASE WHEN category='operations' THEN amount ELSE 0 END) ops, SUM(CASE WHEN category='development' THEN amount ELSE 0 END) dev, SUM(CASE WHEN category='capacity' THEN amount ELSE 0 END) cap, SUM(CASE WHEN category='lead_acquisition_cost' THEN amount ELSE 0 END) lac FROM ledger WHERE day>=99 GROUP BY day ORDER BY day"""): print(r)
print('Ad channel day>=99:')
for r in q("""SELECT day,channel_id,group_id,spend,leads_generated, CASE WHEN spend>0 THEN 1000.0*leads_generated/spend END lpk FROM ad_channel_leads WHERE day>=99 ORDER BY day,group_id,channel_id"""): print(r)
print('Ad agg:')
for r in q("""SELECT group_id,channel_id,SUM(spend) spend,SUM(leads_generated) leads, 1000.0*SUM(leads_generated)/SUM(spend) lpk FROM ad_channel_leads WHERE day>=99 GROUP BY group_id,channel_id ORDER BY group_id,channel_id"""): print(r)
print('Issues open:')
for r in q("""SELECT group_id, COUNT(*) n, AVG(days_open) avg_age, MAX(days_open) max_age, SUM(CASE WHEN days_open>=2 THEN 1 ELSE 0 END) age2p, SUM(CASE WHEN days_open>=7 THEN 1 ELSE 0 END) age7p, SUM(CASE WHEN open_day>=99 THEN 1 ELSE 0 END) opened_week FROM issues WHERE status='open' GROUP BY group_id ORDER BY n DESC"""): print(r)
print('Issues resolved recent:')
for r in q("""SELECT group_id,COUNT(*) n,AVG(days_open) avg_days,MAX(days_open) maxdays FROM issues WHERE status='resolved' AND resolved_day>=99 GROUP BY group_id ORDER BY n DESC"""): print(r)
print('Daily usage group:')
for r in q("""SELECT du.day,c.group_id,COUNT(DISTINCT du.customer_id) users,SUM(du.usage_units) usage FROM daily_usage du JOIN customers c ON c.customer_id=du.customer_id WHERE du.day>=99 GROUP BY du.day,c.group_id ORDER BY du.day,c.group_id"""): print(r)
print('Open enterprise threads summary:')
for r in q("""SELECT thread_id, customer_id, group_id, day, sender, status, closed, LEFT(message,120) msg FROM enterprise_turns WHERE closed=0 ORDER BY day ASC LIMIT 20"""): print(r)
print('Research projects:')
for r in q("""SELECT * FROM research_projects ORDER BY expected_completion_day"""): print(r)
print('Config overrides last 10:')
for r in q("""SELECT id,day,tool_name,setting_type,settings_json FROM config_overrides ORDER BY id DESC LIMIT 10"""): print(r)
print('Social API:')
try:
    posts=nm.analytics.get_social_posts(days=14, limit=80)
    print(posts if isinstance(posts,str) else json.dumps(posts,indent=2))
except Exception as e: print(e)
print('Group insights:')
for gid in ['S2','S3','D_S07','S1','E1','E2','E3','D_E02','D_E09']:
    try:
        gi=nm.market.get_group_insights(gid)
        print('\n---%s---'%gid)
        print(gi if isinstance(gi,str) else json.dumps(gi,indent=2))
    except Exception as e: print('err',gid,e)
print('Research API:')
try:
    pr=nm.research.list_research_projects(); print(pr if isinstance(pr,str) else json.dumps(pr,indent=2))
except Exception as e: print(e)

import novamind_api as nm, json
results=[]
for i in range(4):
    try:
        r=nm.market.research_market()
    except Exception as e:
        r={'error':str(e)}
    results.append(r)
print(json.dumps(results, indent=2))
print('cash ledger research since 105?', nm.query("SELECT category,SUM(amount) amt,COUNT(*) n FROM ledger WHERE day>=105 GROUP BY category ORDER BY category")['rows'])
print('known', json.dumps(nm.market.get_market_overview(), indent=2))

